Greedy insertion with marginal cost scoring and fallback to new empty assign if all attempts fail.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		deltaCost float64
		ok        bool
	}
	for jj := range oris {
		bestCandidate := candidate{-1, 0, false}
		// try existing assigns first
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			origCost := dispatch.Assigns[ii].Cost
			if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					delta := dispatch.Assigns[ii].Cost - origCost
					if !bestCandidate.ok || delta < bestCandidate.deltaCost {
						bestCandidate = candidate{ii, delta, true}
					}
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}
		// try using a new empty assign if allowed
		if dispatch.AssignsLen < MAXASSIGNS {
			newIdx := dispatch.AssignsLen
			dispatch.Assigns[newIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[newIdx].GenRoute()
			if dispatch.Assigns[newIdx].Cost >= 0 {
				delta := dispatch.Assigns[newIdx].Cost
				if !bestCandidate.ok || delta < bestCandidate.deltaCost {
					bestCandidate = candidate{newIdx, delta, true}
				}
			}
			if bestCandidate.assignIdx != newIdx {
				dispatch.Assigns[newIdx].RemoveShip(total_ship + jj)
				dispatch.Assigns[newIdx].GenRoute()
			}
		}
		// perform the actual insertion
		if bestCandidate.ok {
			ai := bestCandidate.assignIdx
			if ai >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
			// remove trial ship if present and re-add cleanly
			dispatch.Assigns[ai].RemoveShip(total_ship + jj)
			dispatch.Assigns[ai].GenRoute()
			dispatch.Assigns[ai].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[ai].GenRoute()
		} else {
			// fallback: create new assign if possible
			if dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship+jj, oris[jj], dess[jj])
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				if dispatch.Assigns[dispatch.AssignsLen].Cost >= 0 {
					dispatch.AssignsLen++
				} else {
					dispatch.Assigns[dispatch.AssignsLen].RemoveShip(total_ship + jj)
					dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

